def last_visited_integers(words):
    nums = []
    result = []
    consecutive_prev = 0

    for word in words:
        if word == "prev":
            consecutive_prev += 1
            if consecutive_prev > len(nums):
                result.append(-1)
            else:
                result.append(nums[-consecutive_prev])
        else:
            consecutive_prev = 0
            nums.append(int(word))

    return result
